// Parse Claude response and extract blueprint
const response = $input.first().json;
let text = '';

// Claude API returns content array
if (response.content && Array.isArray(response.content)) {
  text = response.content.map(c => c.text || '').join('');
} else if (typeof response === 'string') {
  text = response;
} else {
  text = JSON.stringify(response);
}

// Remove markdown code blocks if present
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let blueprint;
try {
  blueprint = JSON.parse(text);
} catch (e) {
  // Try to find JSON object in text
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    blueprint = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse blueprint JSON: ' + e.message);
  }
}

// Validate required fields
if (!blueprint.meta) throw new Error('Blueprint missing meta field');
if (!blueprint.sections || !Array.isArray(blueprint.sections)) {
  throw new Error('Blueprint missing sections array');
}

// Flatten image prompts from all sections
const imagePrompts = [];
for (const section of blueprint.sections) {
  if (section.media?.images) {
    for (const img of section.media.images) {
      imagePrompts.push({
        sectionId: section.id,
        prompt: img.prompt,
        alt: img.alt || img.prompt
      });
    }
  }
}

return [{
  json: {
    blueprint,
    imagePrompts,
    hasImages: imagePrompts.length > 0
  }
}];

// Split image prompts into individual items for DALL-E processing
const data = $input.first().json;
const items = data.imagePrompts.map(ip => ({
  json: {
    sectionId: ip.sectionId,
    prompt: ip.prompt,
    alt: ip.alt,
    blueprint: data.blueprint
  }
}));
return items;

// Merge generated images back into blueprint
const items = $input.all();
let blueprint = items[0].json.blueprint || $items('Split Image Prompts').first().json.blueprint;

// Deep clone blueprint
blueprint = JSON.parse(JSON.stringify(blueprint));

// Map generated image URLs back to sections
for (const item of items) {
  const sectionId = item.json.sectionId;
  const imageUrl = item.json.data?.[0]?.url || item.json.url || '';

  const section = blueprint.sections.find(s => s.id === sectionId);
  if (section) {
    if (!section.media) section.media = {};
    if (!section.media.generatedImages) section.media.generatedImages = [];
    section.media.generatedImages.push({
      url: imageUrl,
      alt: item.json.alt || ''
    });
  }
}

return [{ json: { blueprint } }];

// Topological sort of sections based on dependencies, then split into items
const blueprint = $input.first().json.blueprint;
const sections = blueprint.sections;

// Build adjacency and in-degree maps
const inDegree = {};
const adj = {};
const sectionMap = {};

for (const s of sections) {
  inDegree[s.id] = 0;
  adj[s.id] = [];
  sectionMap[s.id] = s;
}

for (const s of sections) {
  if (s.dependencies && Array.isArray(s.dependencies)) {
    for (const dep of s.dependencies) {
      if (adj[dep]) {
        adj[dep].push(s.id);
        inDegree[s.id]++;
      }
    }
  }
}

// Kahn's algorithm for topological sort
const queue = [];
for (const id in inDegree) {
  if (inDegree[id] === 0) queue.push(id);
}

const sorted = [];
while (queue.length > 0) {
  const current = queue.shift();
  sorted.push(current);
  for (const neighbor of adj[current]) {
    inDegree[neighbor]--;
    if (inDegree[neighbor] === 0) queue.push(neighbor);
  }
}

// If cycle detected, just use original order
const orderedSections = sorted.length === sections.length
  ? sorted.map(id => sectionMap[id])
  : sections;

// Split into individual items for the Switch node
return orderedSections.map((section, index) => ({
  json: {
    section,
    sectionIndex: index,
    totalSections: orderedSections.length,
    blueprint: { meta: blueprint.meta, global: blueprint.global },
    fx: section.fx || { engine: 'gsap', config: {} }
  }
}));

// Generate Spline embed code for the section
const section = $json.section;
const config = $json.fx.config || {};
const splineUrl = config.sceneUrl || config.url || 'https://prod.spline.design/placeholder/scene.splinecode';

const html = `<section id="${section.id}" class="spline-section" style="position:relative;width:100%;min-height:100vh;overflow:hidden;">
  <div class="spline-container" style="position:absolute;inset:0;z-index:0;">
    <iframe src="${splineUrl}" frameborder="0" width="100%" height="100%" style="border:none;" loading="lazy"></iframe>
  </div>
  <div class="spline-overlay" style="position:relative;z-index:1;padding:4rem 2rem;">
    <h2 style="font-size:3rem;font-weight:700;">${section.heading || ''}</h2>
    ${section.subheading ? '<p style="font-size:1.25rem;opacity:0.8;">' + section.subheading + '</p>' : ''}
    ${section.content ? '<div class="content">' + section.content + '</div>' : ''}
  </div>
</section>`;

return [{
  json: {
    ...($json),
    generatedCode: html,
    codeType: 'html',
    engine: 'spline'
  }
}];

// Handle Creatify section with Pexels video fallback
const section = $json.section || $input.first().json.section;
const config = section?.fx?.config || {};
const pexelsData = $json.videos || $input.first().json.videos;

let videoUrl = config.videoUrl || '';
let videoSource = 'creatify';

// Use Pexels fallback if available
if (pexelsData && Array.isArray(pexelsData) && pexelsData.length > 0) {
  const vid = pexelsData[0];
  const file = vid.video_files?.find(f => f.quality === 'hd') || vid.video_files?.[0];
  if (file?.link) {
    videoUrl = file.link;
    videoSource = 'pexels';
  }
}

const html = `<section id="${section.id}" class="creatify-section" style="position:relative;width:100%;min-height:100vh;overflow:hidden;">
  <div class="video-bg" style="position:absolute;inset:0;z-index:0;">
    <video autoplay muted loop playsinline style="width:100%;height:100%;object-fit:cover;" ${videoUrl ? 'src="' + videoUrl + '"' : ''}>
      <source src="${videoUrl}" type="video/mp4">
    </video>
  </div>
  <div class="video-overlay" style="position:relative;z-index:1;padding:4rem 2rem;background:rgba(0,0,0,0.4);">
    <h2 style="font-size:3rem;font-weight:700;color:#fff;">${section.heading || ''}</h2>
    ${section.subheading ? '<p style="font-size:1.25rem;color:rgba(255,255,255,0.8);">' + section.subheading + '</p>' : ''}
    ${section.content ? '<div style="color:#fff;">' + section.content + '</div>' : ''}
  </div>
</section>`;

return [{
  json: {
    ...($input.first().json),
    generatedCode: html,
    codeType: 'html',
    engine: 'creatify',
    videoSource,
    videoUrl
  }
}];

// Generate GSAP/CSS animated section
const section = $json.section;
const config = $json.fx?.config || {};
const palette = $json.blueprint?.meta?.palette || ['#0a0a0a','#1a1a2e','#16213e','#0f3460','#e94560'];

const animationType = config.animation || 'fadeInUp';
const duration = config.duration || 1;
const stagger = config.stagger || 0.2;

const html = `<section id="${section.id}" class="gsap-section" style="position:relative;width:100%;min-height:100vh;display:flex;flex-direction:column;justify-content:center;align-items:center;padding:4rem 2rem;background:${palette[0]};color:#fff;overflow:hidden;">
  <h2 class="gsap-animate" data-animation="${animationType}" style="font-size:3.5rem;font-weight:800;margin-bottom:1rem;opacity:0;">${section.heading || ''}</h2>
  ${section.subheading ? '<p class="gsap-animate" data-animation="' + animationType + '" style="font-size:1.5rem;opacity:0;margin-bottom:2rem;color:' + palette[4] + ';">' + section.subheading + '</p>' : ''}
  ${section.content ? '<div class="gsap-animate content" data-animation="' + animationType + '" style="opacity:0;max-width:800px;text-align:center;line-height:1.8;font-size:1.1rem;">' + section.content + '</div>' : ''}
</section>
<script>
  if (typeof gsap !== "undefined" && typeof ScrollTrigger !== "undefined") {
    gsap.registerPlugin(ScrollTrigger);
    document.querySelectorAll('#${section.id} .gsap-animate').forEach((el, i) => {
      gsap.fromTo(el,
        { opacity: 0, y: 60 },
        { opacity: 1, y: 0, duration: ${duration}, delay: i * ${stagger},
          scrollTrigger: { trigger: el, start: 'top 80%', toggleActions: 'play none none reverse' }
        }
      );
    });
  }
</script>`;

return [{
  json: {
    ...($json),
    generatedCode: html,
    codeType: 'html',
    engine: 'gsap'
  }
}];

// Assemble all generated sections into a complete website file structure
const items = $input.all();
const meta = items[0]?.json?.blueprint?.meta || { title: 'Web Factory Site', palette: ['#0a0a0a','#1a1a2e','#16213e','#0f3460','#e94560'], fonts: { heading: 'Inter', body: 'Inter' } };

// Collect all section HTML
const sectionsHtml = items.map(item => item.json.generatedCode || '').join('\n\n');

// Check which engines are used
const engines = new Set(items.map(item => item.json.engine).filter(Boolean));

// Build CDN links
const cdnLinks = [];
if (engines.has('threejs')) {
  cdnLinks.push('<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r152/three.min.js"></script>');
}
if (engines.has('gsap')) {
  cdnLinks.push('<script src="https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.2/gsap.min.js"></script>');
  cdnLinks.push('<script src="https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.2/ScrollTrigger.min.js"></script>');
}

const palette = meta.palette || ['#0a0a0a','#1a1a2e','#16213e','#0f3460','#e94560'];

// Generate index.html
const indexHtml = `<!DOCTYPE html>
<html lang="${meta.lang || 'it'}">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${meta.title || 'Web Factory Site'}</title>
  <meta name="description" content="${meta.description || ''}">
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link href="https://fonts.googleapis.com/css2?family=${encodeURIComponent(meta.fonts?.heading || 'Inter')}:wght@400;700;800&family=${encodeURIComponent(meta.fonts?.body || 'Inter')}:wght@400;500;600&display=swap" rel="stylesheet">
  <link rel="stylesheet" href="style.css">
  ${cdnLinks.join('\n  ')}
</head>
<body>
  <div id="app">
${sectionsHtml}
  </div>
  <script src="main.js"></script>
</body>
</html>`;

// Generate style.css
const styleCss = `/* Web Factory v2 ├ó┬Ç┬ö Auto-generated styles */
:root {
  --color-bg: ${palette[0]};
  --color-surface: ${palette[1]};
  --color-primary: ${palette[2]};
  --color-secondary: ${palette[3]};
  --color-accent: ${palette[4]};
  --font-heading: '${meta.fonts?.heading || 'Inter'}', sans-serif;
  --font-body: '${meta.fonts?.body || 'Inter'}', sans-serif;
}

* { margin: 0; padding: 0; box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--font-body);
  background: var(--color-bg);
  color: #fff;
  overflow-x: hidden;
}
h1, h2, h3, h4, h5, h6 { font-family: var(--font-heading); }
a { color: var(--color-accent); text-decoration: none; }
a:hover { text-decoration: underline; }
img, video { max-width: 100%; height: auto; }
.gsap-section, .spline-section, .creatify-section, .threejs-section {
  position: relative;
  width: 100%;
  min-height: 100vh;
}
@media (max-width: 768px) {
  h2 { font-size: 2rem !important; }
  p { font-size: 1rem !important; }
  section { padding: 2rem 1rem !important; }
}`;

// Generate main.js
const mainJs = `// Web Factory v2 ├ó┬Ç┬ö Main JavaScript
document.addEventListener('DOMContentLoaded', () => {
  console.log('Web Factory v2 ├ó┬Ç┬ö Site loaded');

  // Smooth scroll for anchor links
  document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function(e) {
      e.preventDefault();
      const target = document.querySelector(this.getAttribute('href'));
      if (target) target.scrollIntoView({ behavior: 'smooth' });
    });
  });

  // Intersection Observer for lazy animations
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('visible');
      }
    });
  }, { threshold: 0.1 });

  document.querySelectorAll('.gsap-animate').forEach(el => observer.observe(el));
});
`;

// Generate package.json (for Vercel)
const packageJson = JSON.stringify({
  name: (meta.title || 'web-factory-site').toLowerCase().replace(/[^a-z0-9]+/g, '-'),
  version: '1.0.0',
  private: true,
  description: meta.description || 'Generated by Web Factory v2'
}, null, 2);

// Generate vercel.json
const vercelJson = JSON.stringify({
  version: 2,
  builds: [
    { src: '*.html', use: '@vercel/static' },
    { src: '*.css', use: '@vercel/static' },
    { src: '*.js', use: '@vercel/static' }
  ],
  routes: [
    { src: '/(.*)', dest: '/index.html' }
  ]
}, null, 2);

return [{
  json: {
    files: [
      { path: 'index.html', content: indexHtml },
      { path: 'style.css', content: styleCss },
      { path: 'main.js', content: mainJs },
      { path: 'package.json', content: packageJson },
      { path: 'vercel.json', content: vercelJson }
    ],
    meta,
    totalFiles: 5
  }
}];

// Prepare files for GitHub push ├ó┬Ç┬ö base64 encode all content
const prevData = $items('Code Organizer File Structure')[0].json;
const repoData = $input.first().json;

// Get repo info ├ó┬Ç┬ö handle both new and existing repos
const repoFullName = repoData.full_name || repoData.owner?.login + '/' + repoData.name || '';
const owner = repoFullName.split('/')[0] || repoData.owner?.login || '';
const repo = repoFullName.split('/')[1] || repoData.name || '';

const files = prevData.files.map(f => ({
  path: f.path,
  content: Buffer.from(f.content, 'utf8').toString('base64'),
  owner,
  repo
}));

return files.map(f => ({ json: f }));
